  1→/**
  2→ * Graph scan: periodic workspace-wide analysis for contradictions and anomalies.
  3→ *
  4→ * Pure query functions that gather scan signals from the workspace graph,
  5→ * then delegate to the observer agent for contradiction analysis.
  6→ *
  7→ * Scan types:
  8→ *   1. Decision-implementation contradictions: confirmed decisions vs completed tasks
  9→ *   2. Stale blocked tasks: tasks blocked longer than threshold (14 days)
 10→ */
 11→
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import type { LanguageModel } from "ai";
 14→import { createObservation, listWorkspaceOpenObservations, type ObserveTargetRecord } from "../observation/queries";
 15→import { logInfo } from "../http/observability";
 16→import { synthesizePatterns, type Anomaly } from "./llm-synthesis";
 17→import { parseEntityRef } from "./evidence-validator";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Types
 21→// ---------------------------------------------------------------------------
 22→
 23→export type ConfirmedDecision = {
 24→  id: RecordId<"decision">;
 25→  summary: string;
 26→  rationale?: string;
 27→};
 28→
 29→export type CompletedTask = {
 30→  id: RecordId<"task">;
 31→  title: string;
 32→  description?: string;
 33→};
 34→
 35→export type StaleBlockedTask = {
 36→  id: RecordId<"task">;
 37→  title: string;
 38→  description?: string;
 39→  updated_at: string | Date;
 40→  daysBlocked: number;
 41→};
 42→
 43→export type StatusDriftTask = {
 44→  id: RecordId<"task">;
 45→  title: string;
 46→  status: string;
 47→  dependency: {
 48→    id: RecordId<"task">;
 49→    title: string;
 50→    status: string;
 51→  };
 52→};
 53→
 54→export type GraphScanResult = {
 55→  contradictions_found: number;
 56→  stale_blocked_found: number;
 57→  status_drift_found: number;
 58→  observations_created: number;
 59→};
 60→
 61→// ---------------------------------------------------------------------------
 62→// Configuration
 63→// ---------------------------------------------------------------------------
 64→
 65→const STALE_BLOCKED_THRESHOLD_DAYS = 14;
 66→
 67→// ---------------------------------------------------------------------------
 68→// Graph queries (pure data gathering)
 69→// ---------------------------------------------------------------------------
 70→
 71→async function queryConfirmedDecisions(
 72→  surreal: Surreal,
 73→  workspaceRecord: RecordId<"workspace", string>,
 74→): Promise<ConfirmedDecision[]> {
 75→  const [rows] = await surreal.query<[ConfirmedDecision[]]>(
 76→    `SELECT id, summary, rationale, created_at FROM decision
 77→     WHERE workspace = $ws AND status = "confirmed"
 78→     ORDER BY created_at DESC
 79→     LIMIT 50;`,
 80→    { ws: workspaceRecord },
 81→  );
 82→  return rows ?? [];
 83→}
 84→
 85→async function queryCompletedTasks(
 86→  surreal: Surreal,
 87→  workspaceRecord: RecordId<"workspace", string>,
 88→): Promise<CompletedTask[]> {
 89→  const [rows] = await surreal.query<[CompletedTask[]]>(
 90→    `SELECT id, title, description, updated_at FROM task
 91→     WHERE workspace = $ws AND status IN ["completed", "done"]
 92→     ORDER BY updated_at DESC
 93→     LIMIT 50;`,
 94→    { ws: workspaceRecord },
 95→  );
 96→  return rows ?? [];
 97→}
 98→
 99→async function queryStaleBlockedTasks(
100→  surreal: Surreal,
101→  workspaceRecord: RecordId<"workspace", string>,
102→): Promise<StaleBlockedTask[]> {
103→  const thresholdDate = new Date(
104→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
105→  );
106→
107→  const [rows] = await surreal.query<
108→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
109→  >(
110→    `SELECT id, title, description, updated_at FROM task
111→     WHERE workspace = $ws
112→       AND status = "blocked"
113→       AND updated_at < $threshold
114→     ORDER BY updated_at ASC
115→     LIMIT 50;`,
116→    { ws: workspaceRecord, threshold: thresholdDate },
117→  );
118→
119→  return (rows ?? []).map((row) => {
120→    const updatedAt = new Date(row.updated_at);
121→    const daysBlocked = Math.floor(
122→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
123→    );
124→    return { ...row, daysBlocked };
125→  });
126→}
127→
128→async function queryStatusDriftTasks(
129→  surreal: Surreal,
130→  workspaceRecord: RecordId<"workspace", string>,
131→): Promise<StatusDriftTask[]> {
132→  // Two-step approach: first find completed tasks with dependencies,
133→  // then filter for incomplete dependencies in application code
134→  const [rows] = await surreal.query<[Array<{
135→    id: RecordId<"task">;
136→    title: string;
137→    status: string;
138→    dep_ids: RecordId<"task">[];
139→    dep_titles: string[];
140→    dep_statuses: string[];
141→  }>]>(
142→    `SELECT
143→       id, title, status,
144→       ->depends_on->task.id AS dep_ids,
145→       ->depends_on->task.title AS dep_titles,
146→       ->depends_on->task.status AS dep_statuses
147→     FROM task
148→     WHERE workspace = $ws
149→       AND status IN ["completed", "done"]
150→       AND array::len(->depends_on->task) > 0
151→     LIMIT 50;`,
152→    { ws: workspaceRecord },
153→  );
154→
155→  return (rows ?? []).flatMap((row) => {
156→    const depIds = row.dep_ids ?? [];
157→    const depTitles = row.dep_titles ?? [];
158→    const depStatuses = row.dep_statuses ?? [];
159→
160→    const drifts: StatusDriftTask[] = [];
161→    for (let i = 0; i < depIds.length; i++) {
162→      const depStatus = depStatuses[i];
163→      if (depStatus !== "completed" && depStatus !== "done") {
164→        drifts.push({
165→          id: row.id,
166→          title: row.title,
167→          status: row.status,
168→          dependency: {
169→            id: depIds[i],
170→            title: depTitles[i],
171→            status: depStatus,
172→          },
173→        });
174→      }
175→    }
176→    return drifts;
177→  });
178→}
179→
180→// ---------------------------------------------------------------------------
181→// Entity-level deduplication query
182→// ---------------------------------------------------------------------------
183→
184→/**
185→ * Queries existing open observer observations linked to a specific entity.
186→ * Used for entity-level dedup -- if the observer already has an open observation
187→ * on this entity, we skip creating another.
188→ */
189→// Static query map: one pre-built query string per allowed table, eliminating
190→// dynamic interpolation at the call site (prevents SurrealQL injection).
191→const OBSERVER_DEDUP_QUERIES: Record<string, string> = Object.fromEntries(
192→  ["project", "feature", "task", "decision", "question", "intent", "git_commit", "observation"].map(
193→    (table) => [
194→      table,
195→      `SELECT text, severity, status FROM observation
196→       WHERE workspace = $ws
197→         AND source_agent = "observer_agent"
198→         AND status IN ["open", "acknowledged"]
199→         AND ->observes->${table}.id CONTAINS $entity
200→       LIMIT 20;`,
201→    ],
202→  ),
203→);
204→
205→async function queryExistingObserverObservationsForEntity(
206→  surreal: Surreal,
207→  workspaceRecord: RecordId<"workspace", string>,
208→  entityRecord: RecordId<string, string>,
209→): Promise<Array<{ text: string; severity: string; status: string }>> {
210→  const query = OBSERVER_DEDUP_QUERIES[entityRecord.table.name];
211→  if (!query) {
212→    throw new Error(`Invalid entity table for observer dedup query: ${entityRecord.table.name}`);
213→  }
214→
215→  const [rows] = await surreal.query<[Array<{ text: string; severity: string; status: string }>]>(
216→    query,
217→    { ws: workspaceRecord, entity: entityRecord },
218→  );
219→  return rows ?? [];
220→}
221→
222→// ---------------------------------------------------------------------------
223→// Contradiction detection (deterministic heuristic)
224→// ---------------------------------------------------------------------------
225→
226→/**
227→ * Simple keyword-based contradiction detection between decisions and tasks.
228→ * Looks for signals that a completed task contradicts a confirmed decision.
229→ *
230→ * Returns pairs of (decision, task) that appear contradictory.
231→ */
232→function detectContradictions(
233→  decisions: ConfirmedDecision[],
234→  tasks: CompletedTask[],
235→): Array<{ decision: ConfirmedDecision; task: CompletedTask }> {
236→  const contradictions: Array<{ decision: ConfirmedDecision; task: CompletedTask }> = [];
237→
238→  for (const decision of decisions) {
239→    const decisionText = decision.summary.toLowerCase();
240→
241→    for (const task of tasks) {
242→      const taskText = `${task.title} ${task.description ?? ""}`.toLowerCase();
243→
244→      // Detect technology contradictions
245→      // e.g., decision says "use tRPC" but task implements "REST" or "Express"
246→      if (detectsTechnologyContradiction(decisionText, taskText)) {
247→        contradictions.push({ decision, task });
248→      }
249→    }
250→  }
251→
252→  return contradictions;
253→}
254→
255→/**
256→ * Detects when a task uses a technology that contradicts a decision mandate.
257→ * Checks known technology pairs (e.g., tRPC vs REST, GraphQL vs REST).
258→ */
259→function detectsTechnologyContradiction(
260→  decisionText: string,
261→  taskText: string,
262→): boolean {
263→  const technologyPairs: Array<{ mandated: string[]; contradicting: string[] }> = [
264→    {
265→      mandated: ["trpc"],
266→      contradicting: ["rest", "express"],
267→    },
268→    {
269→      mandated: ["graphql"],
270→      contradicting: ["rest", "express"],
271→    },
272→    {
273→      mandated: ["typescript"],
274→      contradicting: ["javascript"],
275→    },
276→  ];
277→
278→  for (const pair of technologyPairs) {
279→    const mandatesThis = pair.mandated.some((term) => decisionText.includes(term));
280→    const taskUsesContradicting = pair.contradicting.some((term) => taskText.includes(term));
281→
282→    if (mandatesThis && taskUsesContradicting) {
283→      return true;
284→    }
285→  }
286→
287→  return false;
288→}
289→
290→// ---------------------------------------------------------------------------
291→// Deduplication
292→// ---------------------------------------------------------------------------
293→
294→type ExistingObservation = {
295→  text: string;
296→  severity: string;
297→  status: string;
298→};
299→
300→function isAlreadyObserved(
301→  existingObservations: ExistingObservation[],
302→  newText: string,
303→  entityId?: string,
304→): boolean {
305→  const normalizedNew = newText.toLowerCase();
306→
307→  return existingObservations.some((obs) => {
308→    if (obs.status === "resolved") return false;
309→
310→    // When entity ID is available, require it to appear in the existing text
311→    // so observations about different entities are never considered duplicates
312→    if (entityId && !obs.text.toLowerCase().includes(entityId.toLowerCase())) {
313→      return false;
314→    }
315→
316→    const normalizedExisting = obs.text.toLowerCase();
317→    // Check if the core issue is already covered using a meaningful prefix
318→    const prefixLen = Math.min(80, normalizedNew.length);
319→    return (
320→      normalizedExisting.includes(normalizedNew.slice(0, prefixLen)) ||
321→      normalizedNew.includes(normalizedExisting.slice(0, prefixLen))
322→    );
323→  });
324→}
325→
326→// ---------------------------------------------------------------------------
327→// Scan orchestrator
328→// ---------------------------------------------------------------------------
329→
330→export async function runGraphScan(
331→  surreal: Surreal,
332→  workspaceRecord: RecordId<"workspace", string>,
333→  observerModel?: LanguageModel,
334→): Promise<GraphScanResult> {
335→  const result: GraphScanResult = {
336→    contradictions_found: 0,
337→    stale_blocked_found: 0,
338→    status_drift_found: 0,
339→    observations_created: 0,
340→  };
341→
342→  // Load existing observations for deduplication
343→  const existingObservations = await listWorkspaceOpenObservations({
344→    surreal,
345→    workspaceRecord,
346→    limit: 100,
347→  });
348→
349→  // 1. Detect decision-implementation contradictions
350→  const [decisions, completedTasks] = await Promise.all([
351→    queryConfirmedDecisions(surreal, workspaceRecord),
352→    queryCompletedTasks(surreal, workspaceRecord),
353→  ]);
354→
355→  const contradictions = detectContradictions(decisions, completedTasks);
356→  result.contradictions_found = contradictions.length;
357→
358→  for (const { decision, task } of contradictions) {
359→    // Entity-level dedup: check if observer already has an open observation on this decision
360→    const existingForDecision = await queryExistingObserverObservationsForEntity(
361→      surreal, workspaceRecord,
362→      decision.id as RecordId<string, string>,
363→    );
364→
365→    const observationText =
366→      `Contradiction detected: Decision "${decision.summary}" conflicts with completed task "${task.title}". ` +
367→      `The task appears to implement an approach that contradicts the confirmed decision.`;
368→
369→    if (existingForDecision.length > 0 || isAlreadyObserved(existingObservations, observationText, decision.id.id as string)) {
370→      logInfo("observer.scan.dedup", "Skipping duplicate contradiction observation", {
371→        decisionId: decision.id.id,
372→        taskId: task.id.id,
373→      });
374→      continue;
375→    }
376→
377→    const now = new Date();
378→    await createObservation({
379→      surreal,
380→      workspaceRecord,
381→      text: observationText,
382→      severity: "conflict",
383→      sourceAgent: "observer_agent",
384→      observationType: "contradiction",
385→      now,
386→      relatedRecord: decision.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
387→    });
388→
389→    result.observations_created += 1;
390→  }
391→
392→  // 2. Detect stale blocked tasks
393→  const staleBlocked = await queryStaleBlockedTasks(surreal, workspaceRecord);
394→  result.stale_blocked_found = staleBlocked.length;
395→
396→  for (const task of staleBlocked) {
397→    // Entity-level dedup: check if observer already has an open observation on this task
398→    const existingForTask = await queryExistingObserverObservationsForEntity(
399→      surreal, workspaceRecord,
400→      task.id as RecordId<string, string>,
401→    );
402→
403→    const observationText =
404→      `Task blocked for ${task.daysBlocked} days: "${task.title}". ` +
405→      `This task has been blocked since ${new Date(task.updated_at).toISOString().slice(0, 10)} ` +
406→      `(exceeds the ${STALE_BLOCKED_THRESHOLD_DAYS}-day threshold).`;
407→
408→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText, task.id.id as string)) {
409→      logInfo("observer.scan.dedup", "Skipping duplicate stale-blocked observation", {
410→        taskId: task.id.id,
411→      });
412→      continue;
413→    }
414→
415→    const now = new Date();
416→    await createObservation({
417→      surreal,
418→      workspaceRecord,
419→      text: observationText,
420→      severity: "warning",
421→      sourceAgent: "observer_agent",
422→      observationType: "anomaly",
423→      now,
424→      relatedRecord: task.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
425→    });
426→
427→    result.observations_created += 1;
428→  }
429→
430→  // 3. Detect status drift (completed tasks with incomplete dependencies)
431→  const driftTasks = await queryStatusDriftTasks(surreal, workspaceRecord);
432→  result.status_drift_found = driftTasks.length;
433→
434→  for (const drift of driftTasks) {
435→    // Entity-level dedup
436→    const existingForTask = await queryExistingObserverObservationsForEntity(
437→      surreal, workspaceRecord,
438→      drift.id as RecordId<string, string>,
439→    );
440→
441→    const observationText =
442→      `Status drift detected: Task "${drift.title}" is marked as ${drift.status}, ` +
443→      `but its dependency "${drift.dependency.title}" is still ${drift.dependency.status}. ` +
444→      `A task should not be completed before its dependencies.`;
445→
446→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText, drift.id.id as string)) {
447→      logInfo("observer.scan.dedup", "Skipping duplicate status-drift observation", {
448→        taskId: drift.id.id,
449→        depTaskId: drift.dependency.id.id,
450→      });
451→      continue;
452→    }
453→
454→    const now = new Date();
455→    await createObservation({
456→      surreal,
457→      workspaceRecord,
458→      text: observationText,
459→      severity: "warning",
460→      sourceAgent: "observer_agent",
461→      observationType: "anomaly",
462→      now,
463→      relatedRecord: drift.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
464→    });
465→
466→    result.observations_created += 1;
467→  }
468→
469→  // 4. LLM pattern synthesis (when model configured and anomalies exist)
470→  if (observerModel) {
471→    const anomalies: Anomaly[] = [];
472→
473→    for (const { decision, task } of contradictions) {
474→      anomalies.push({
475→        type: "contradiction",
476→        text: `Decision "${decision.summary}" conflicts with task "${task.title}"`,
477→        entityId: decision.id.id as string,
478→        entityTable: "decision",
479→      });
480→    }
481→    for (const task of staleBlocked) {
482→      anomalies.push({
483→        type: "stale_blocked",
484→        text: `Task "${task.title}" blocked for ${task.daysBlocked} days`,
485→        entityId: task.id.id as string,
486→        entityTable: "task",
487→      });
488→    }
489→    for (const drift of driftTasks) {
490→      anomalies.push({
491→        type: "status_drift",
492→        text: `Task "${drift.title}" completed but dependency "${drift.dependency.title}" is ${drift.dependency.status}`,
493→        entityId: drift.id.id as string,
494→        entityTable: "task",
495→      });
496→    }
497→
498→    if (anomalies.length > 0) {
499→      const patterns = await synthesizePatterns(observerModel, anomalies);
500→
501→      if (patterns) {
502→        for (const pattern of patterns) {
503→          // Dedup: check if a similar pattern observation already exists
504→          const patternText = `${pattern.pattern_name}: ${pattern.description}`;
505→          if (isAlreadyObserved(existingObservations, patternText)) {
506→            logInfo("observer.scan.synthesis_dedup", "Skipping duplicate pattern", {
507→              pattern: pattern.pattern_name,
508→            });
509→            continue;
510→          }
511→
512→          // Build related records from contributing entities
513→          const relatedRecords: ObserveTargetRecord[] = [];
514→          for (const ref of pattern.contributing_entities) {
515→            const parsed = parseEntityRef(ref);
516→            if (parsed) {
517→              relatedRecords.push(new RecordId(parsed.table, parsed.id) as ObserveTargetRecord);
518→            }
519→          }
520→
521→          const now = new Date();
522→          await createObservation({
523→            surreal,
524→            workspaceRecord,
525→            text: patternText,
526→            severity: pattern.severity,
527→            sourceAgent: "observer_agent",
528→            observationType: "pattern",
529→            now,
530→            relatedRecords: relatedRecords.length > 0 ? relatedRecords : undefined,
531→          });
532→
533→          result.observations_created += 1;
534→        }
535→
536→        logInfo("observer.scan.synthesis", "Pattern synthesis completed", {
537→          patternsFound: patterns.length,
538→        });
539→      } else {
540→        logInfo("observer.llm.fallback", "Pattern synthesis failed, anomalies reported individually", {
541→          anomalyCount: anomalies.length,
542→        });
543→      }
544→    }
545→  }
546→
547→  logInfo("observer.scan.completed", "Graph scan completed", {
548→    workspaceId: workspaceRecord.id,
549→    ...result,
550→  });
551→
552→  return result;
553→}
