  1→/**
  2→ * LLM synthesis: effect boundary for generateObject calls in pattern synthesis pipeline.
  3→ *
  4→ * Takes anomalies from deterministic graph scan and synthesizes named patterns.
  5→ * Uses AbortSignal.timeout(10_000) for latency control.
  6→ * Returns undefined on any failure.
  7→ */
  8→
  9→import { generateObject, type LanguageModel } from "ai";
 10→import { logError, logInfo } from "../http/observability";
 11→import { contradictionDetectionResultSchema, synthesisResultSchema, type DetectedContradiction, type SynthesisPattern } from "./schemas";
 12→
 13→export type Anomaly = {
 14→  type: "contradiction" | "stale_blocked" | "status_drift";
 15→  text: string;
 16→  entityId: string;
 17→  entityTable: string;
 18→};
 19→
 20→/**
 21→ * Synthesizes anomalies into named patterns via LLM.
 22→ * Returns patterns with min 2 contributing entities, or undefined on failure.
 23→ */
 24→export async function synthesizePatterns(
 25→  model: LanguageModel,
 26→  anomalies: Anomaly[],
 27→): Promise<SynthesisPattern[] | undefined> {
 28→  if (anomalies.length === 0) return [];
 29→
 30→  const start = Date.now();
 31→
 32→  // Partition large workspaces: top 20 per type
 33→  const partitioned = partitionAnomalies(anomalies, 20);
 34→
 35→  try {
 36→    const anomaliesText = partitioned.map((a) =>
 37→      `- [${a.entityTable}:${a.entityId}] (${a.type}) ${a.text}`,
 38→    ).join("\n");
 39→
 40→    const result = await generateObject({
 41→      model,
 42→      schema: synthesisResultSchema,
 43→      prompt: `You are a pattern synthesis agent analyzing workspace anomalies to identify systemic patterns.
 44→
 45→## Anomalies Detected
 46→${anomaliesText}
 47→
 48→## Instructions
 49→Analyze these anomalies and identify higher-level patterns:
 50→- "bottleneck_decision" = single decision blocking multiple tasks
 51→- "cascade_block" = chain of blocked items
 52→- "priority_drift" = priorities inconsistent with actions
 53→- "stale_cluster" = group of stale items in same area
 54→- "contradiction_cluster" = multiple contradictions sharing a root cause
 55→
 56→Rules:
 57→- Each pattern MUST reference at least 2 contributing entities using table:id format
 58→- Only include entities from the anomalies listed above
 59→- If no meaningful patterns emerge, return an empty patterns array
 60→- Set severity to "conflict" only for active contradictions`,
 61→      abortSignal: AbortSignal.timeout(10_000),
 62→    });
 63→
 64→    const latencyMs = Date.now() - start;
 65→    logInfo("observer.llm.synthesis", "LLM pattern synthesis completed", {
 66→      latencyMs,
 67→      patternCount: result.object.patterns.length,
 68→    });
 69→
 70→    // Filter patterns with < 2 contributing entities (schema enforces min 2, but defense in depth)
 71→    return result.object.patterns.filter((p) => p.contributing_entities.length >= 2);
 72→  } catch (error) {
 73→    const latencyMs = Date.now() - start;
 74→    logError("observer.llm.synthesis_error", "LLM pattern synthesis failed", {
 75→      error,
 76→      latencyMs,
 77→    });
 78→    return undefined;
 79→  }
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Contradiction detection (LLM-based)
