  1→/**
  2→ * Milestone 3: Observer Agent Core and Periodic Graph Scan
  3→ *
  4→ * Traces: Story 5 (Observer Agent Core), Story 7 (Periodic Graph Scan)
  5→ *
  6→ * Validates:
  7→ * - Observer Agent uses ToolLoopAgent pattern with correct tools
  8→ * - Observer Agent returns structured output (observations_created, verdict, evidence)
  9→ * - Graph scan detects decision-implementation contradictions
 10→ * - Graph scan detects stale blocked tasks
 11→ * - Graph scan deduplicates against existing open observations
 12→ *
 13→ * Driving ports:
 14→ *   POST /api/observe/:table/:id          (EVENT target)
 15→ *   POST /api/observe/scan/:workspaceId   (periodic scan trigger)
 16→ */
 17→import { describe, expect, it, beforeAll } from "bun:test";
 18→import { RecordId } from "surrealdb";
 19→import {
 20→  setupObserverSuite,
 21→  wireObserverEvents,
 22→  setupObserverWorkspace,
 23→  createTaskWithCommit,
 24→  createConfirmedDecision,
 25→  createObservationByAgent,
 26→  triggerTaskCompletion,
 27→  triggerGraphScan,
 28→  waitForObservation,
 29→  getWorkspaceObservations,
 30→  createTestUser,
 31→  createTestWorkspace,
 32→  createReadyTask,
 33→} from "./observer-test-kit";
 34→
 35→const getRuntime = setupObserverSuite("observer_m3_agent_scan");
 36→
 37→beforeAll(async () => {
 38→  const { surreal, port } = getRuntime();
 39→  await wireObserverEvents(surreal, port);
 40→});
 41→
 42→// =============================================================================
 43→// Story 5: Observer Agent Core
 44→// =============================================================================
 45→
 46→describe("Milestone 3: Observer Agent Core (Story 5)", () => {
 47→  // ---------------------------------------------------------------------------
 48→  // S5-1: Observer Agent returns structured output
 49→  // ---------------------------------------------------------------------------
 50→  it("observer agent produces structured verification output for task completion", async () => {
 51→    const { baseUrl, surreal } = getRuntime();
 52→
 53→    // Given a workspace with a task linked to a source commit
 54→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "agent-output");
 55→    const { taskId } = await createTaskWithCommit(surreal, workspaceId, {
 56→      title: "Implement user session expiry",
 57→      status: "in_progress",
 58→      repository: "org/brain",
 59→    });
 60→
 61→    // When the task is completed and the observer agent processes it
 62→    await triggerTaskCompletion(surreal, taskId);
 63→
 64→    // Then the observer creates observations with structured metadata
 65→    const observations = await waitForObservation(surreal, "task", taskId, 30_000);
 66→    expect(observations.length).toBeGreaterThanOrEqual(1);
 67→
 68→    const obs = observations[0];
 69→    // And the observation carries the observer's structured fields
 70→    expect(obs.source_agent).toBe("observer_agent");
 71→    expect(obs.text).toBeTruthy();
 72→    expect(obs.severity).toBeDefined();
 73→    // And the observation is linked to the task
 74→    const edges = (await surreal.query(
 75→      `SELECT ->observes->task AS targets FROM $obs;`,
 76→      { obs: obs.id },
 77→    )) as Array<Array<{ targets: RecordId[] }>>;
 78→    expect(edges[0]?.[0]?.targets).toHaveLength(1);
 79→  }, 120_000);
 80→
 81→  // ---------------------------------------------------------------------------
 82→  // S5-2: Observer Agent uses workspace context
 83→  // ---------------------------------------------------------------------------
 84→  it("observer agent considers existing workspace observations in its analysis", async () => {
 85→    const { baseUrl, surreal } = getRuntime();
 86→
 87→    // Given a workspace with a pre-existing warning observation about stability
 88→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "agent-context");
 89→
 90→    await createObservationByAgent(surreal, workspaceId, "pm_agent", {
 91→      text: "Multiple tasks in this project have been completed without review",
 92→      severity: "warning",
 93→      observationType: "pattern",
 94→    });
 95→
 96→    const { taskId } = await createTaskWithCommit(surreal, workspaceId, {
 97→      title: "Remove deprecated API endpoints",
 98→      status: "in_progress",
 99→      repository: "org/brain",
100→    });
101→
102→    // When another task is completed in this workspace
103→    await triggerTaskCompletion(surreal, taskId);
104→
105→    // Then the observer creates an observation (it has access to workspace context)
106→    const observations = await waitForObservation(surreal, "task", taskId, 30_000);
107→    expect(observations.length).toBeGreaterThanOrEqual(1);
108→    expect(observations[0].source_agent).toBe("observer_agent");
109→  }, 120_000);
110→});
111→
112→// =============================================================================
113→// Story 7: Periodic Graph Scan
114→// =============================================================================
115→
116→describe("Milestone 3: Periodic Graph Scan (Story 7)", () => {
117→  // ---------------------------------------------------------------------------
118→  // S7-1: Graph scan detects decision-implementation contradiction
119→  // ---------------------------------------------------------------------------
120→  it("graph scan detects a contradiction between a confirmed decision and completed task", async () => {
121→    const { baseUrl, surreal } = getRuntime();
122→
123→    // Given a workspace with a confirmed decision to use tRPC for all endpoints
124→    const user = await createTestUser(baseUrl, "scan-contradiction");
125→    const workspace = await createTestWorkspace(baseUrl, user);
126→
127→    const { decisionId } = await createConfirmedDecision(surreal, workspace.workspaceId, {
128→      summary: "Use tRPC for all new API endpoints",
129→      rationale: "Type safety and consistency across the codebase",
130→    });
131→
132→    // And a completed task that implemented a REST endpoint instead
133→    const task = await createReadyTask(surreal, workspace.workspaceId, {
134→      title: "Add billing API endpoint using Express REST",
135→      description: "Implemented billing API as REST endpoint with Express router",
136→      status: "completed",
137→    });
138→
139→    // Link the task to the same project as the decision
140→    // (both belong to the workspace, creating a detectable contradiction)
141→
142→    // When the periodic graph scan runs
143→    const scanResponse = await triggerGraphScan(baseUrl, workspace.workspaceId, user.headers);
144→
145→    // Then the scan detects the contradiction
146→    expect(scanResponse.ok).toBe(true);
147→
