#### Evalite Pattern Example
**File:** `evals/chat-agent.eval.ts`

```typescript
import { evalite } from "evalite";
import { beforeAll, afterAll } from "vitest";

const cases: ChatAgentTestCase[] = [
  {
    id: "plan-work",
    userMessage: "I want to build...",
    expectsToolUse: true,
    expectedTools: ["invoke_pm_agent"],
  },
  // ... more cases
];

evalite<ChatAgentTestCase, ChatAgentEvalOutput, ChatAgentTestCase>(
  "Chat Agent Behavioral Correctness",
  {
    data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
    task: async (input) => runChatAgentCase(input),
    scorers: [
      {
        name: "tool-invoked",
        description: "Agent used tools when action was expected...",
        scorer: ({ output, expected }) => scoreToolInvoked(output, expected),
      },
      // ... more scorers
    ],
    columns: ({ input, output, scores }) => [
      { label: "Model", value: chatAgentModelId! },
      { label: "Case", value: input.id },
      // ... more columns
    ],
  }
);
```

#### Scorer Pattern
**Files:** `evals/scorers/tool-invoked.ts`, `evals/scorers/correct-tool-selection.ts`

```typescript
// Simple binary scorer
export function scoreToolInvoked(output: ChatAgentEvalOutput, expected: ChatAgentTestCase): number {
  const usedTools = output.toolNames.length > 0;
  if (expected.expectsToolUse) {
    return usedTools ? 1 : 0;
  }
  return usedTools ? 0 : 1;
}

// Ratio-based scorer
export function scoreCorrectToolSelection(output: ChatAgentEvalOutput, expected: ChatAgentTestCase): number {
  if (!expected.expectedTools || expected.expectedTools.length === 0) return 1;
  const calledTools = new Set(output.toolNames);
  const matches = expected.expectedTools.filter((t) => calledTools.has(t));
  return matches.length / expected.expectedTools.length;
}
```

