172→async function runObserverLlmCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
173→  try {
174→    if (testCase.evalType === "verification") {
175→      return await runVerificationCase(testCase);
176→    }
177→    return await runPeerReviewCase(testCase);
178→  } catch (error) {
179→    return {
180→      caseId: testCase.id,
181→      verdict: "",
182→      reasoning: "",
183→      severity: "",
184→      evidenceRefs: [],
185→      success: false,
