191→async function runVerificationCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
192→  const taskRecord = seedResult.tasks.get(testCase.seedCaseKey);
193→  if (!taskRecord) {
194→    throw new Error(`No seeded task for case key: ${testCase.seedCaseKey}`);
195→  }
196→
197→  const taskId = taskRecord.id as string;
198→
199→  // Build entity context (loads related decisions from graph)
200→  const context = await buildEntityContext(
201→    runtime.surreal,
202→    seedResult.workspaceRecord,
203→    "task",
204→    taskId,
205→  );
206→
207→  // Provide a minimal deterministic result for the LLM to enhance
208→  const deterministicResult = {
209→    verdict: "inconclusive" as const,
210→    severity: "info" as const,
211→    verified: false,
212→    text: "Deterministic check: no external signals available.",
213→  };
214→
215→  const llmVerdict = await generateVerificationVerdict(observerModel, context, deterministicResult);
216→  const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
217→
218→  return {
219→    caseId: testCase.id,
220→    verdict: finalVerdict.verdict,
221→    confidence: finalVerdict.confidence,
222→    reasoning: finalVerdict.text,
223→    severity: finalVerdict.severity,
224→    evidenceRefs: finalVerdict.evidenceRefs ?? [],
225→    success: true,
226→  };
227→}
228→
229→async function runPeerReviewCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
230→  const obsRecord = seedResult.observations.get(testCase.seedCaseKey);
231→  if (!obsRecord) {
232→    throw new Error(`No seeded observation for case key: ${testCase.seedCaseKey}`);
233→  }
234→
235→  const obsId = obsRecord.id as string;
236→
237→  // Load the observation details
238→  const [obsRows] = await runtime.surreal.query<[Array<{
239→    text: string;
240→    severity: string;
241→    source_agent: string;
242→  }>]>(
243→    `SELECT text, severity, source_agent FROM $obs;`,
244→    { obs: new RecordId("observation", obsId) },
245→  );
246→  const obs = obsRows?.[0];
247→  if (!obs) throw new Error(`Observation not found: ${obsId}`);
248→
249→  // Load linked entities via observes edges
250→  const [edgeRows] = await runtime.surreal.query<[Array<{ out: RecordId }>]>(
251→    `SELECT out FROM observes WHERE in = $obs;`,
252→    { obs: new RecordId("observation", obsId) },
253→  );
254→
255→  const linkedEntities: Array<{ table: string; id: string; title: string; description?: string }> = [];
256→  for (const row of edgeRows ?? []) {
257→    const targetTable = row.out.table.name;
258→    const targetId = row.out.id as string;
259→    const [details] = await runtime.surreal.query<[Array<{
260→      title?: string; summary?: string; text?: string; description?: string;
261→    }>]>(
262→      `SELECT title, summary, text, description FROM $record;`,
263→      { record: new RecordId(targetTable, targetId) },
264→    );
265→    const d = details?.[0];
266→    linkedEntities.push({
267→      table: targetTable,
268→      id: targetId,
269→      title: d?.title ?? d?.summary ?? d?.text ?? "Unknown",
270→      description: d?.description,
271→    });
272→  }
273→
274→  const llmVerdict = await generatePeerReviewVerdict(
275→    observerModel,
276→    obs.text,
277→    obs.severity,
278→    obs.source_agent,
279→    linkedEntities,
280→  );
281→
282→  if (!llmVerdict) {
283→    return {
284→      caseId: testCase.id,
285→      verdict: "inconclusive",
286→      reasoning: "LLM peer review failed",
287→      severity: "info",
288→      evidenceRefs: [],
289→      success: false,
290→      error: "LLM returned undefined",
291→    };
292→  }
293→
294→  return {
295→    caseId: testCase.id,
296→    verdict: llmVerdict.verdict === "sound" ? "match" : llmVerdict.verdict === "unsupported" ? "mismatch" : "inconclusive",
297→    confidence: llmVerdict.confidence,
298→    reasoning: llmVerdict.reasoning,
299→    severity: llmVerdict.verdict === "unsupported" ? "warning" : "info",
300→    evidenceRefs: [],
301→    success: true,
302→  };
303→}
