  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { createDeterministicIdGenerator } from "./eval-test-kit";
  3→
  4→export type ObserverLlmSeedResult = {
  5→  workspaceRecord: RecordId<"workspace", string>;
  6→  projectRecord: RecordId<"project", string>;
  7→  /** Decisions seeded in the project, keyed by case ID */
  8→  decisions: Map<string, RecordId<"decision", string>>;
  9→  /** Tasks seeded in the project, keyed by case ID */
 10→  tasks: Map<string, RecordId<"task", string>>;
 11→  /** Observations seeded by non-observer agents, keyed by case ID */
 12→  observations: Map<string, RecordId<"observation", string>>;
 13→};
 14→
 15→export async function seedObserverLlmTestData(surreal: Surreal): Promise<ObserverLlmSeedResult> {
 16→  const nextId = createDeterministicIdGenerator("observer-llm-eval");
 17→  const now = new Date();
 18→  const oneMonthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
 19→  const twoWeeksAgo = new Date(now.getTime() - 15 * 24 * 60 * 60 * 1000);
 20→
 21→  // Workspace
 22→  const workspaceRecord = new RecordId("workspace", nextId()) as RecordId<"workspace", string>;
 23→  await surreal.create(workspaceRecord).content({
 24→    name: "Observer LLM Eval Workspace",
 25→    status: "active",
 26→    onboarding_complete: true,
 27→    onboarding_turn_count: 5,
 28→    onboarding_summary_pending: false,
 29→    onboarding_started_at: oneMonthAgo,
 30→    created_at: oneMonthAgo,
 31→    updated_at: now,
 32→  });
 33→
 34→  // Owner identity (member_of requires identity, not person)
 35→  const ownerRecord = new RecordId("identity", nextId());
 36→  await surreal.create(ownerRecord).content({
