 29→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 30→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 31→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 32→const schemaPath = join(process.cwd(), "schema", "surreal-schema.surql");
