283→function buildSeedEntityContent(kind: string, text: string, now: Date): Record<string, unknown> {
284→  const base = { created_at: now, updated_at: now };
285→  if (kind === "project") return { ...base, name: text, status: "active" };
286→  if (kind === "feature") return { ...base, name: text, status: "active" };
287→  if (kind === "task") return { ...base, title: text, status: "open" };
288→  if (kind === "decision") return { ...base, summary: text, status: "extracted" };
289→  return { ...base, text, status: "open" };
290→}
