 40→evalite<SuggestionGoldenCase, SuggestionsEvalOutput, SuggestionGoldenCase>("Onboarding Suggestions Golden Cases", {
 41→  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
 42→  task: async (input) => runCase(input),
