 59→function scoreByName(
 60→  scores: Array<{ name: string; score: number | null }>,
 61→  name: string,
 62→): number {
 63→  const match = scores.find((score) => score.name === name);
 64→  if (!match || match.score === null || Number.isNaN(match.score)) {
 65→    throw new Error(`Missing score for scorer: ${name}`);
 66→  }
