267→): Promise<number> {
268→  const wsRecord = new RecordId("workspace", workspaceId);
269→  let query = `SELECT count() AS count FROM observation WHERE workspace = $ws`;
270→  const params: Record<string, unknown> = { ws: wsRecord };
271→
272→  if (filters.observationType) {
273→    query += ` AND observation_type = $obsType`;
274→    params.obsType = filters.observationType;
275→  }
276→  if (filters.sourceAgent) {
277→    query += ` AND source_agent = $agent`;
278→    params.agent = filters.sourceAgent;
279→  }
280→  if (filters.source) {
281→    query += ` AND source = $source`;
282→    params.source = filters.source;
283→  }
284→  if (filters.status) {
285→    query += ` AND status = $status`;
286→    params.status = filters.status;
287→  }
288→
289→  query += ` GROUP ALL;`;
290→
291→  const rows = (await surreal.query(query, params)) as Array<Array<{ count: number }>>;
