373→    targetId?: string;
374→  },
375→): Promise<{ observationId: string }> {
376→  const observationId = `obs-${crypto.randomUUID()}`;
377→  const observationRecord = new RecordId("observation", observationId);
378→  const workspaceRecord = new RecordId("workspace", workspaceId);
379→
380→  await surreal.query(`CREATE $obs CONTENT $content;`, {
381→    obs: observationRecord,
382→    content: {
383→      text: opts.text,
384→      severity: opts.severity,
385→      status: "open",
386→      observation_type: opts.observationType,
387→      source_agent: sourceAgent,
388→      workspace: workspaceRecord,
389→      created_at: new Date(),
390→    },
391→  });
392→
393→  // Link observation to target entity if provided
394→  if (opts.targetTable && opts.targetId) {
395→    const targetRecord = new RecordId(opts.targetTable, opts.targetId);
396→    await surreal.query(
397→      `RELATE $obs->observes->$target SET added_at = time::now();`,
398→      { obs: observationRecord, target: targetRecord },
399→    );
400→  }
401→
402→  return { observationId };
403→}
