  1→/**
  2→ * Milestone 3: Decision Verification and Pattern Synthesis
  3→ *
  4→ * Traces: Roadmap Phase 03 (03-01, 03-02)
  5→ *   - US-2 (AC-1.7): Decision confirmation triggers check against completed tasks
  6→ *   - US-3a (AC-2.1 through AC-2.7): Pattern synthesis from anomalies
  7→ *   - US-3b (AC-2.4): Pattern deduplication across scans
  8→ *   - R4: Cross-signal pattern synthesis
  9→ *   - R10: Large workspace handling
 10→ *
 11→ * IMPORTANT: These tests call a real LLM. OBSERVER_MODEL must be set in .env.
 12→ *
 13→ * Validates that:
 14→ * - Decision confirmation triggers LLM check against completed tasks
 15→ * - Graph scan passes anomalies to LLM for pattern synthesis
 16→ * - Patterns require minimum 2 contributing entities
 17→ * - Pattern observations have observation_type=pattern
 18→ * - Empty anomaly list skips LLM
 19→ * - Duplicate patterns are not recreated across scans
 20→ *
 21→ * Driving ports:
 22→ *   POST /api/observe/decision/:id       (SurrealQL EVENT target)
 23→ *   POST /api/observe/scan/:workspaceId  (periodic graph scan)
 24→ *   SurrealDB direct queries             (verification of outcomes)
 25→ */
 26→import { describe, expect, it, beforeAll } from "bun:test";
 27→import { RecordId } from "surrealdb";
 28→import {
 29→  setupObserverSuite,
 30→  wireObserverEvents,
 31→  setupObserverWorkspace,
 32→  triggerDecisionConfirmation,
 33→  triggerGraphScan,
 34→  waitForObservation,
 35→  getObservationsForEntity,
 36→  getWorkspaceObservations,
 37→  createProject,
 38→  createTaskInProject,
 39→  createDecisionInProject,
 40→  createConfirmedDecision,
 41→  countObservations,
 42→} from "./llm-reasoning-test-kit";
 43→import { createTestUser } from "../coding-agent-orchestrator/orchestrator-test-kit";
 44→
 45→const getRuntime = setupObserverSuite("observer_llm_m3_decision_synthesis");
 46→
 47→beforeAll(async () => {
 48→  const { surreal, port } = getRuntime();
 49→  await wireObserverEvents(surreal, port);
 50→});
 51→
 52→// =============================================================================
 53→// AC-1.7: Decision confirmation checks against completed tasks
 54→// =============================================================================
 55→
 56→describe("Milestone 3: Decision Verification (AC-1.7)", () => {
 57→  it("newly confirmed decision is checked against completed tasks in same project", async () => {
 58→    const { baseUrl, surreal } = getRuntime();
 59→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-dec-verify");
 60→    const { projectId } = await createProject(surreal, workspaceId, "Decision Check Project");
 61→
 62→    // Given 2 completed tasks in the project
 63→    const { taskId: taskId1 } = await createTaskInProject(surreal, workspaceId, projectId, {
 64→      title: "Implement billing API with REST endpoints",
 65→      description: "Built RESTful billing API using Express with JSON responses",
 66→      status: "completed",
 67→    });
 68→
 69→    const { taskId: taskId2 } = await createTaskInProject(surreal, workspaceId, projectId, {
 70→      title: "Add GraphQL gateway for frontend queries",
 71→      description: "Built a GraphQL gateway to aggregate multiple backend services",
 72→      status: "completed",
 73→    });
 74→
 75→    // And a decision in proposed status (not yet confirmed)
 76→    const { decisionId } = await createDecisionInProject(surreal, workspaceId, projectId, {
 77→      summary: "Standardize on tRPC for all API endpoints. No REST or GraphQL for new services.",
 78→      rationale: "End-to-end type safety and reduced boilerplate",
 79→      status: "proposed",
 80→    });
 81→
 82→    // When the decision is confirmed
 83→    await triggerDecisionConfirmation(surreal, decisionId, "confirmed");
 84→
 85→    // Then the observer evaluates completed tasks against the new decision
 86→    const observations = await waitForObservation(surreal, "decision", decisionId, 60_000);
 87→    expect(observations.length).toBeGreaterThanOrEqual(1);
 88→
 89→    // And at least one observation is from the observer agent
 90→    const observerObs = observations.filter((o) => o.source_agent === "observer_agent");
 91→    expect(observerObs.length).toBeGreaterThanOrEqual(1);
 92→
 93→    // And the observation references the decision
 94→    expect(observerObs[0].text).toBeTruthy();
 95→  }, 120_000);
 96→
 97→  it("no LLM call when confirmed decision has no completed tasks in project", async () => {
 98→    const { baseUrl, surreal } = getRuntime();
 99→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-dec-empty");
100→    const { projectId } = await createProject(surreal, workspaceId, "Empty Tasks Project");
101→
102→    // Given a proposed decision with NO completed tasks in the project
103→    const { decisionId } = await createDecisionInProject(surreal, workspaceId, projectId, {
104→      summary: "Use event sourcing for all state management",
105→      status: "proposed",
106→    });
107→
108→    // When the decision is confirmed
109→    await triggerDecisionConfirmation(surreal, decisionId, "confirmed");
110→
111→    // Then an observation is still created (the event fires)
112→    const observations = await waitForObservation(surreal, "decision", decisionId, 60_000);
113→    expect(observations.length).toBeGreaterThanOrEqual(1);
114→
115→    const obs = observations[0];
116→    expect(obs.source_agent).toBe("observer_agent");
117→    // And the observation is informational (no tasks to contradict)
118→    expect(obs.severity).toBe("info");
119→  }, 120_000);
120→});
