122→// =============================================================================
123→// AC-2.1 through AC-2.7: Pattern Synthesis
124→// =============================================================================
125→
126→describe("Milestone 3: Pattern Synthesis (AC-2.1 - AC-2.7)", () => {
127→  // ---------------------------------------------------------------------------
128→  // AC-2.5: Empty anomaly list skips LLM
129→  // ---------------------------------------------------------------------------
130→  it("scan with no anomalies returns empty result without LLM call", async () => {
131→    const { baseUrl, surreal } = getRuntime();
132→    const user = await createTestUser(baseUrl, "scan-empty");
133→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-scan-empty");
134→
135→    // Given a workspace with no anomalies (clean state)
136→    // When the scan is triggered
137→    const response = await triggerGraphScan(baseUrl, workspaceId, user.headers);
138→
139→    // Then the scan completes successfully
140→    expect(response.ok).toBe(true);
141→
142→    // And no pattern observations are created
143→    const patternCount = await countObservations(surreal, workspaceId, {
144→      observationType: "pattern",
145→    });
146→    expect(patternCount).toBe(0);
147→  }, 60_000);
148→
149→  // ---------------------------------------------------------------------------
150→  // AC-2.1: Anomalies passed to LLM after deterministic scan
151→  // ---------------------------------------------------------------------------
152→  it("scan with anomalies triggers LLM synthesis and creates pattern observations", async () => {
153→    const { baseUrl, surreal } = getRuntime();
154→    const user = await createTestUser(baseUrl, "scan-anomalies");
155→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-scan-anoms");
156→    const { projectId } = await createProject(surreal, workspaceId, "Anomaly Project");
157→
158→    // Given multiple tasks blocked by a single decision (creates anomaly conditions)
159→    const { decisionId } = await createDecisionInProject(surreal, workspaceId, projectId, {
160→      summary: "Use TypeScript exclusively for all code. No Python, Go, or other languages.",
161→      rationale: "Single-language codebase simplifies tooling",
162→    });
163→
164→    // Create several tasks that conflict with this decision
165→    for (const title of [
166→      "Build Python data pipeline for ML model training",
167→      "Add Go microservice for high-performance ingestion",
168→      "Implement Python test framework for data validation",
169→    ]) {
170→      const { taskId } = await createTaskInProject(surreal, workspaceId, projectId, {
171→        title,
172→        status: "in_progress",
173→      });
174→      // Mark as blocked and set stale date (>14 days) so the scan detects them
175→      const taskRecord = new RecordId("task", taskId);
176→      const staleDate = new Date(Date.now() - 20 * 24 * 60 * 60 * 1000); // 20 days ago
177→      await surreal.query(
178→        `UPDATE $task SET status = "blocked", updated_at = $date;`,
179→        { task: taskRecord, date: staleDate },
180→      );
181→    }
182→
183→    // When the scan is triggered
184→    const response = await triggerGraphScan(baseUrl, workspaceId, user.headers);
185→    expect(response.ok).toBe(true);
186→
187→    // Allow time for LLM synthesis
188→    await Bun.sleep(5_000);
189→
190→    // Then observations are created in the workspace
191→    const allObs = await getWorkspaceObservations(surreal, workspaceId, "observer_agent");
192→    expect(allObs.length).toBeGreaterThanOrEqual(1);
193→  }, 120_000);
194→
195→  // ---------------------------------------------------------------------------
196→  // AC-2.3: Pattern observation links to contributing entities
197→  // ---------------------------------------------------------------------------
198→  it("pattern observation has observation_type=pattern", async () => {
199→    const { baseUrl, surreal } = getRuntime();
200→    const user = await createTestUser(baseUrl, "scan-pattern-type");
201→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-scan-type");
202→    const { projectId } = await createProject(surreal, workspaceId, "Pattern Type Project");
203→
204→    // Given a workspace with conditions that produce a systemic pattern
205→    // (multiple stale blocked tasks from the same cause)
206→    const { decisionId } = await createDecisionInProject(surreal, workspaceId, projectId, {
207→      summary: "All deployments require manual QA approval before production",
208→      rationale: "Quality gate",
209→    });
210→
211→    for (let i = 0; i < 3; i++) {
212→      const { taskId } = await createTaskInProject(surreal, workspaceId, projectId, {
213→        title: `Deploy feature ${i + 1} to production (blocked by QA)`,
214→        status: "blocked",
215→      });
216→      // Set old created_at to make them stale
217→      const taskRecord = new RecordId("task", taskId);
218→      const staleDate = new Date(Date.now() - 20 * 24 * 60 * 60 * 1000); // 20 days ago
219→      await surreal.query(
220→        `UPDATE $task SET created_at = $date, updated_at = $date;`,
221→        { task: taskRecord, date: staleDate },
222→      );
223→    }
224→
225→    // When the scan is triggered
226→    await triggerGraphScan(baseUrl, workspaceId, user.headers);
227→    await Bun.sleep(5_000);
228→
229→    // Then check for pattern-type observations
230→    const patternObs = await getWorkspaceObservations(surreal, workspaceId, "observer_agent");
231→    const patterns = patternObs.filter((o) => o.observation_type === "pattern");
232→
233→    // Pattern observations should exist if LLM synthesis found correlations
234→    // (This is a soft assertion — LLM may or may not synthesize a pattern)
235→    if (patterns.length > 0) {
236→      expect(patterns[0].observation_type).toBe("pattern");
237→      expect(patterns[0].text).toBeTruthy();
238→    }
239→  }, 120_000);
240→
241→  // ---------------------------------------------------------------------------
242→  // AC-2.4: Deduplication prevents repeated pattern observations
243→  // ---------------------------------------------------------------------------
244→  it("running scan twice does not create duplicate pattern observations", async () => {
245→    const { baseUrl, surreal } = getRuntime();
246→    const user = await createTestUser(baseUrl, "scan-dedup");
247→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-scan-dedup");
248→    const { projectId } = await createProject(surreal, workspaceId, "Dedup Project");
249→
250→    // Given a workspace with anomaly conditions
251→    await createDecisionInProject(surreal, workspaceId, projectId, {
252→      summary: "No database schema changes without migration scripts",
253→    });
254→    for (let i = 0; i < 3; i++) {
255→      await createTaskInProject(surreal, workspaceId, projectId, {
256→        title: `Schema change ${i + 1} without migration`,
257→        status: "blocked",
258→      });
259→    }
260→
261→    // When scan is triggered the first time
262→    await triggerGraphScan(baseUrl, workspaceId, user.headers);
263→    await Bun.sleep(5_000);
264→    const countAfterFirst = await countObservations(surreal, workspaceId, {
265→      sourceAgent: "observer_agent",
266→    });
267→
268→    // And scan is triggered a second time
269→    await triggerGraphScan(baseUrl, workspaceId, user.headers);
270→    await Bun.sleep(5_000);
271→    const countAfterSecond = await countObservations(surreal, workspaceId, {
272→      sourceAgent: "observer_agent",
273→    });
274→
275→    // Then the observation count should not increase (deduplication)
276→    expect(countAfterSecond).toBe(countAfterFirst);
277→  }, 180_000);
278→});
